import{_ as a,o as t,c as i,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Meta AEM Technical Setup","description":"","frontmatter":{"title":"Meta AEM Technical Setup","slug":"meta-aem-technical-setup"},"headers":[],"relativePath":"developer-hub/meta-aem-technical-setup.md","filePath":"developer-hub/meta-aem-technical-setup.md"}'),n={name:"developer-hub/meta-aem-technical-setup.md"};function o(s,e,l,p,d,c){return t(),i("div",null,[...e[0]||(e[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>With iOS 14.5 and later, Apple&#39;s App Tracking Transparency (ATT) framework requires apps to request user permission before accessing the Identifier for Advertisers (IDFA). When users decline tracking permission (which is often the case), traditional attribution methods become limited. To address this challenge, Meta introduced <strong>Aggregated Event Measurement (AEM)</strong>.</p><p>Meta&#39;s AEM is a privacy-preserving protocol that allows measurement of web and app events from iOS 14.5+ devices, <em>even when users have opted out of tracking</em>.</p><h3 id="campaign-support" tabindex="-1">Campaign support <a class="header-anchor" href="#campaign-support" aria-label="Permalink to &quot;Campaign support&quot;">​</a></h3><p>AEM supports two kinds of Meta campaigns:</p><table tabindex="0"><thead><tr><th>Campaign Type</th><th>Technical Requirements</th></tr></thead><tbody><tr><td>Mobile App Engagement (MAE)</td><td><strong>Requires</strong> deep linking configuration (<a href="https://help.branch.io/developers-hub/docs/ios-universal-links" target="_blank" rel="noreferrer">iOS Universal Links</a> or <a href="https://help.branch.io/docs/advanced-link-configuration" target="_blank" rel="noreferrer">URI schemes</a>). <code>campaign_ids</code> must be passed through deep links.</td></tr><tr><td>Mobile App Install (MAI)</td><td>Works automatically once AEM is enabled. No additional deep linking configuration is required.</td></tr></tbody></table><h3 id="how-aem-works" tabindex="-1">How AEM works <a class="header-anchor" href="#how-aem-works" aria-label="Permalink to &quot;How AEM works&quot;">​</a></h3><p>Instead of using device-level identifiers like IDFA, AEM utilizes aggregate identifiers:</p><table tabindex="0"><thead><tr><th>Identifier</th><th>Description</th></tr></thead><tbody><tr><td><code>campaign_ids</code></td><td>A set of IDs found on some links that open the app from Facebook ads persisted for 7 days and forwarded to Facebook for campaign optimization. <strong>Required</strong> for <a href="./enable-app-aggregated-event-measurement-support.html#campaign-support">MAE</a> campaigns.</td></tr><tr><td><code>anon_id</code></td><td>An ID generated automatically by the Branch SDK, persisted on install and forwarded to Facebook for campaign optimization. Available for <a href="https://github.com/BranchMetrics/ios-branch-deep-linking-attribution/releases/tag/2.1.2" target="_blank" rel="noreferrer">SDK v2.1.2</a>+. <strong>Optional</strong> for <a href="./enable-app-aggregated-event-measurement-support.html#campaign-support">MAE</a> campaigns.</td></tr></tbody></table><p>These identifiers are forwarded to Facebook through all conversion events for re-engagement campaign optimization.</p><h2 id="implementation-prerequisites" tabindex="-1">Implementation prerequisites <a class="header-anchor" href="#implementation-prerequisites" aria-label="Permalink to &quot;Implementation prerequisites&quot;">​</a></h2><h3 id="sdk-requirements" tabindex="-1">SDK requirements <a class="header-anchor" href="#sdk-requirements" aria-label="Permalink to &quot;SDK requirements&quot;">​</a></h3><ol><li><p>Implement the Branch iOS SDK into your mobile app.</p><ol><li>Minimum version: <a href="https://github.com/BranchMetrics/ios-branch-deep-linking-attribution/releases/tag/2.1.2" target="_blank" rel="noreferrer">SDK v2.1.2</a></li><li>Recommended version: <a href="https://github.com/BranchMetrics/ios-branch-deep-linking-attribution/releases" target="_blank" rel="noreferrer">latest</a></li></ol></li><li><p>Coordinate with your marketing team to <a href="./ad-partner-integration-guide.html">enable the Facebook integration</a> in Branch.</p></li></ol><h3 id="technical-requirements" tabindex="-1">Technical requirements <a class="header-anchor" href="#technical-requirements" aria-label="Permalink to &quot;Technical requirements&quot;">​</a></h3><p>The technical requirements for AEM depend on your <a href="./enable-app-aggregated-event-measurement-support.html#campaign-support">campaign type</a>.</p><p><strong>For all AEM campaigns (MAI and MAE)</strong>:</p><ul><li>Ensure your event Postbacks in Branch are configured to send events to Meta (coordinate with your marketing team on event mappings).</li></ul><p><strong>For MAE campaigns</strong>:</p><ul><li>Your app must support <a href="https://help.branch.io/developers-hub/docs/ios-universal-links" target="_blank" rel="noreferrer">iOS Universal Links</a> or <a href="https://help.branch.io/docs/advanced-link-configuration" target="_blank" rel="noreferrer">URI schemes</a>.</li><li>Your app must properly handle <a href="./deep-link-reference.html">deep links</a> in Meta campaigns.</li></ul><p><strong>For MAI campaigns</strong>:</p><ul><li>MAI campaigns work automatically once AEM is enabled. No additional deep linking configuration is required.</li></ul><h2 id="set-custom-anonymous-id" tabindex="-1">Set custom anonymous ID <a class="header-anchor" href="#set-custom-anonymous-id" aria-label="Permalink to &quot;Set custom anonymous ID&quot;">​</a></h2><p>This step is <strong>optional</strong>. Branch automatically creates and sets a GUID for the <code>anon_id</code> field and sends that to Facebook. <strong>Most implementations do not need to modify this setting.</strong></p><p>However, you may want to set a custom <code>anon_id</code> if you:</p><ul><li>Have an existing user identification system you want to align with across platforms.</li><li>Need to maintain consistent IDs across multiple attribution providers.</li><li>Have specific user privacy or identifier requirements unique to your app.</li></ul><p>If you determine you need a custom ID, use the <code>setAnonID</code> method:</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-5D-50" id="tab-2TVY64M" checked><label data-title="Swift" for="tab-2TVY64M">Swift</label><input type="radio" name="group-5D-50" id="tab-fY13S5d"><label data-title="Objective-C" for="tab-fY13S5d">Objective-C</label></div><div class="blocks"><div class="language-swift vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">swift</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Branch.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">setAnonID</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;your-custom-anon-id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><div class="language-objectivec vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">objectivec</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Branch setAnonID:@&quot;your-custom-anon-id&quot;];</span></span></code></pre></div></div></div><h2 id="testing-and-verification" tabindex="-1">Testing and verification <a class="header-anchor" href="#testing-and-verification" aria-label="Permalink to &quot;Testing and verification&quot;">​</a></h2><h3 id="verify-event-implementation" tabindex="-1">Verify event implementation <a class="header-anchor" href="#verify-event-implementation" aria-label="Permalink to &quot;Verify event implementation&quot;">​</a></h3><p><strong>In your app</strong>:</p><ul><li>Trigger a test event (e.g., make a test purchase).</li><li>Check Branch <a href="https://dashboard.branch.io/overview/events" target="_blank" rel="noreferrer">Liveview</a> to confirm the event appears.</li><li>Verify the event includes any required parameters (like revenue for purchases).</li></ul><p><strong>In Meta Events Manager</strong>:</p><ul><li>Coordinate with your marketing team to verify events appear in Meta Events Manager.</li><li>Check for any errors or warnings about event eligibility.</li></ul><div class="info custom-block"><p class="custom-block-title">Note</p><p>Event data typically appears within minutes to hours after configuration, but allow up to 24 hours for full propagation through Meta&#39;s systems.</p></div><h2 id="aem-data-structure" tabindex="-1">AEM data structure <a class="header-anchor" href="#aem-data-structure" aria-label="Permalink to &quot;AEM data structure&quot;">​</a></h2><p>AEM provides the following campaign-level data in Branch:</p><ul><li><code>campaign_id</code> - Meta campaign identifier</li><li><code>ad_id</code> - Ad identifier</li><li><code>creative_id</code> - Creative identifier</li><li><code>secondary_publisher</code> - Placement (Instagram, Facebook, Audience Network, etc.)</li><li><code>ad_set_id</code> - Ad set identifier</li></ul><h4 id="data-limitations" tabindex="-1">Data limitations <a class="header-anchor" href="#data-limitations" aria-label="Permalink to &quot;Data limitations&quot;">​</a></h4><p>Due to Meta&#39;s privacy-preserving approach, the <code>campaign_name</code> field will show as <code>Unpopulated</code> in Branch reports and exports. This is a Meta limitation that affects all mobile measurement partners using AEM.</p><h2 id="learn-more" tabindex="-1">Learn more <a class="header-anchor" href="#learn-more" aria-label="Permalink to &quot;Learn more&quot;">​</a></h2><p>For more on Branch&#39;s iOS attribution approach, see <a href="./ios-attribution-best-practices.html">iOS Attribution Best Practices</a>.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><details><summary>If an advertiser also uses the Facebook SDK for iOS, what should they do to enable App AEM?</summary><p>If an advertiser uses both the Branch SDK and the Facebook SDK for iOS, they can pass the events in their app campaigns through either method. As a best practice ensure that the install and post-install events use the same preferred connection method by following <a href="https://www.facebook.com/business/help/3215014965459549" target="_blank" rel="noreferrer">these steps from Facebook</a>.</p></details><details><summary>Why does my event data say &quot;Ineligible&quot;?</summary><p>You may run into this issue if AEM was toggled on in the Branch Dashboard before setting up AEM in Meta. AEM must be set up in Meta first, then enabled in the Branch Dashboard.</p><p>If you&#39;ve already run into this issue, coordinate with your marketing team to toggle AEM off and back on again in the Branch Dashboard.</p></details><details><summary>How long until I see AEM data after enabling?</summary><p><strong>Event mapping changes</strong>: Within minutes to hours for events to start flowing. Allow up to 24 hours for full propagation through Meta&#39;s systems.<br><strong>After enabling AEM</strong>: New events should appear once campaigns are running.<br><strong>First campaign data</strong>: Allow 24-48 hours after launching your first AEM campaign to see meaningful data.<br><strong>After toggling AEM off/on</strong>: If you need to retoggle the AEM switch, allow a few hours for data flow to resume.</p></details><details><summary>Why aren&#39;t my Mobile App Engagement (MAE) campaigns getting attributed?</summary><p>For MAE re-engagement campaigns specifically, attribution requires proper deep linking configuration.</p><p><strong>Check the following</strong>:</p><ul><li>Verify <a href="https://help.branch.io/developers-hub/docs/ios-universal-links" target="_blank" rel="noreferrer">iOS Universal Links</a> or <a href="./advanced-link-configuration.html">URI Schemes</a> are properly configured.</li><li>Test that your app opens properly when a <a href="./ad-links.html">Branch Ad Link</a> is clicked from Meta ads.</li><li>Confirm the <code>campaign_ids</code> field is being passed through the Branch Ad Link.</li><li>Check that <a href="./deep-link-reference.html">deep link handling</a> is implemented correctly in your app.</li><li>Ensure you completed the deep linking requirements in the &quot;<a href="./enable-app-aggregated-event-measurement-support.html#technical-requirements">Technical Requirements</a>&quot; section.</li><li>Coordinate with your marketing team to verify MAE campaigns are set to open your app (not web) in Meta.</li></ul><p><strong>To test deep linking</strong>:</p><ol><li>Have your marketing team create a test MAE campaign in Meta that includes a Branch Ad Link.</li><li>Click the ad from a test device.</li><li>Verify the app opens and doesn&#39;t redirect to web.</li><li>Check Branch <a href="https://dashboard.branch.io/overview/events" target="_blank" rel="noreferrer">Liveview</a> to see if the deep link data is received.</li></ol></details>',46)])])}const m=a(n,[["render",o]]);export{u as __pageData,m as default};
